#!/usr/bin/env python3
"""Send Telegram message to Discord DM"""
import requests
import sys

DISCORD_TOKEN = os.environ.get("DISCORD_BOT_TOKEN", "")
DISCORD_DM_CHANNEL = "1501849094589779978"

def send_to_discord(text):
    if text.startswith("[DC] "):
        return True

    try:
        headers = {
            "Authorization": f"Bot {DISCORD_TOKEN}",
            "Content-Type": "application/json"
        }
        payload = {
            "content": f"[TG] {text}"
        }
        r = requests.post(
            f"https://discord.com/api/v10/channels/{DISCORD_DM_CHANNEL}/messages",
            headers=headers,
            json=payload,
            timeout=10
        )
        return r.status_code == 200
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        return False

if __name__ == "__main__":
    import os
    text = sys.argv[1] if len(sys.argv) > 1 else sys.stdin.read().strip()
    if text:
        ok = send_to_discord(text)
        sys.exit(0 if ok else 1)

